import { NextRequest, NextResponse } from 'next/server'
import { auth }                       from '@/auth'
import { fetchGitHubRepos }           from '@/lib/api/github.api'

/**
 * GET /api/github/repos?page=1
 *
 * Lists the authenticated user's GitHub repositories using the GitHub OAuth
 * access token captured during sign-in with GitHub.
 *
 * Returns 403 if the user hasn't connected GitHub (credentials-only login).
 */
export async function GET(req: NextRequest) {
  const session = await auth()

  // Signed-out users — not the same as "no Nest JWT": GitHub-only sign-in has
  // `githubAccessToken` but often no `accessToken` (Nest issues that on credentials login).
  if (!session?.user) {
    return NextResponse.json({ message: 'Unauthorized' }, { status: 401 })
  }

  if (!session.githubAccessToken) {
    return NextResponse.json(
      { message: 'GitHub not connected. Sign in with GitHub to access your repositories.' },
      { status: 403 },
    )
  }

  const page = Number(req.nextUrl.searchParams.get('page') ?? '1')

  try {
    const repos = await fetchGitHubRepos(session.githubAccessToken, page)
    return NextResponse.json(repos)
  } catch (err) {
    console.error('[GET /api/github/repos]', err)
    return NextResponse.json({ message: 'Failed to fetch GitHub repositories' }, { status: 502 })
  }
}
